import json

lines = open('ios_crash.ips').readlines()
metadata = json.loads(lines[0])
crash = json.loads(''.join(lines[1:]))

print("=== Metadata ===")
for k in ['app_name', 'bundleID', 'app_version', 'build_version', 'os_version', 'slice_uuid']:
    print(f"  {k}: {metadata.get(k, '?')}")

print("\n=== Termination ===")
for k in ['termination', 'vmregioninfo', 'vmRegionInfo']:
    if k in crash:
        print(f"  {k}: {crash[k]}")

# Find SampleMAUI images
images = crash.get('usedImages', [])
print("\n=== SampleMAUI and .NET Images ===")
for i, img in enumerate(images):
    name = img.get('name', '')
    if 'SampleMAUI' in name or 'libcoreclr' in name or 'libmono' in name or 'libSystem.' in name:
        print(f"  [{i}] {name}  UUID: {img.get('uuid','')}  base: 0x{img.get('base',0):x}  arch: {img.get('arch','?')}")
        if 'path' in img:
            print(f"       path: {img['path']}")

# Look at Thread 0 SampleMAUI frames specifically
print("\n=== Thread 0 SampleMAUI frames (bridge/managed code) ===")
ft = crash['threads'][crash.get('faultingThread', 0)]
for i, f in enumerate(ft['frames']):
    idx = f.get('imageIndex', -1)
    if 0 <= idx < len(images):
        img = images[idx]
        name = img.get('name', '')
        if 'SampleMAUI' in name:
            base = img.get('base', 0)
            offset = f.get('imageOffset', 0)
            addr = base + offset
            print(f"  #{i:2d}  {name} UUID:{img.get('uuid','')}  0x{addr:x}  (offset 0x{offset:x})")

# Check for any other interesting keys
print("\n=== Last Exception Backtrace SampleMAUI frames ===")
leb = crash.get('lastExceptionBacktrace', [])
for i, f in enumerate(leb):
    idx = f.get('imageIndex', -1)
    if 0 <= idx < len(images):
        img = images[idx]
        name = img.get('name', '')
        if 'SampleMAUI' in name:
            base = img.get('base', 0)
            offset = f.get('imageOffset', 0)
            addr = base + offset
            print(f"  #{i:2d}  {name} UUID:{img.get('uuid','')}  0x{addr:x}  (offset 0x{offset:x})")

# Check for any exception info in the crash
print("\n=== Other diagnostic fields ===")
for key in ['extMods', 'coalitionName', 'isCorpse', 'processLifespan']:
    if key in crash:
        print(f"  {key}: {crash[key]}")

# Thread names
print("\n=== Thread names/dispatch queues ===")
for i, t in enumerate(crash.get('threads', [])):
    name = t.get('name', '')
    queue = t.get('queue', '')
    triggered = t.get('triggered', False)
    info = []
    if name: info.append(f"name='{name}'")
    if queue: info.append(f"queue='{queue}'")
    if triggered: info.append("TRIGGERED")
    if info:
        print(f"  Thread {i}: {', '.join(info)}")
